//
//  BluetoothManager.swift
//  Radiacode
//
//  Created by Pavel Marinchenko on 14.03.2023.
//

import Foundation
import CoreBluetooth
import Combine

/// Менеджер работы с блютуз
protocol BluetoothManager: AnyObject {

    /// Найдено новое устройство
    var observeDevice: AnyPublisher<RadiaCode, Never> { get }

    /// Статус поиска устройств
    var observeScanningStatus: AnyPublisher<Bool, Never> { get }

    /// Запускает поиск устройств
    func startScan()

    /// Останавливает поиск устройств
    func stopScan()

    /// Устанавливает соединение с устройством
    /// - Parameter device: устройство
    func connect(device: CBPeripheral)

    /// Разъеденение с устройством
    /// - Parameter device: устройство
    func disconnect(device: CBPeripheral) async throws

    /// Переподключение устройства
    /// - Parameter cbPeripheral: устройство
    func setupReconnection(device: CBPeripheral)

    /// Статус устройства
    var bluetoothStatus: CurrentValueSubject<BluetoothStatus, Never> { get }
}

final class BluetoothManagerImpl: NSObject {

    private enum Consts {
        static let radiaCodeServiceCBUUID = CBUUID(string: "E63215E5-7003-49D8-96B0-B024798FB901")
    }

    private let centralManager: CBCentralManager

    private let searchingObserver: PassthroughSubject<Bool, Never> = .init()
    private let bleStatusObserver: CurrentValueSubject<Bool, Never> = .init(false)
    private let devicesObserver: PassthroughSubject<RadiaCode, Never> = .init()
    var bluetoothStatus: CurrentValueSubject<BluetoothStatus, Never> = .init(.unknown)

    private var cancellable: Set<AnyCancellable> = .init()
    private var reconnectionCancellable: AnyCancellable?
    private var disconnectContinuation: CheckedContinuation<Void, Error>?

    private let bleQueue: DispatchQueue = .init(label: "com.radiacode.bluetooth.scan", qos: .background)

    override init() {
        centralManager = CBCentralManager(delegate: nil, queue: bleQueue, options: nil)
        super.init()
        centralManager.delegate = self
        setupObservers()
    }
}

// MARK: - BluetoothManagerProtocol

extension BluetoothManagerImpl: BluetoothManager {

    var observeDevice: AnyPublisher<RadiaCode, Never> {
        devicesObserver.eraseToAnyPublisher()
    }

    var observeScanningStatus: AnyPublisher<Bool, Never> {
        centralManager.publisher(for: \.isScanning)
            .assertNoFailure()
            .removeDuplicates()
            .eraseToAnyPublisher()
    }

    func startScan() {
        searchingObserver.send(true)
    }

    func stopScan() {
        centralManager.stopScan()
        searchingObserver.send(false)
    }

    func connect(device: CBPeripheral) {
        centralManager.connect(device, options: [CBConnectPeripheralOptionNotifyOnDisconnectionKey: true])
    }

    func disconnect(device: CBPeripheral) async throws {
        try await withCheckedThrowingContinuation { continuation in
            disconnectContinuation = continuation
            centralManager.cancelPeripheralConnection(device)
        }
    }

    func setupReconnection(device: CBPeripheral) {
        reconnectionCancellable = bleStatusObserver
            .filter { $0 }
            .sink { [weak self] _ in
                guard let self = self else { return }
                self.connect(device: device)
            }
    }
}

// MARK: - Private methods
private extension BluetoothManagerImpl {

    func setupObservers() {
        bleStatusObserver.combineLatest(searchingObserver)
            .assertNoFailure()
            .map { $0 && $1 }
            .sink { [weak self] isReady in
                guard let self = self else { return }
                if isReady {
                    // self.centralManager.retrieveConnectedPeripherals(withServices: [CBUUID])
                    self.centralManager.scanForPeripherals(withServices: [Consts.radiaCodeServiceCBUUID], options: [CBCentralManagerScanOptionAllowDuplicatesKey: true])
                }
            }
            .store(in: &cancellable)
    }
}

// MARK: - CBCentralManagerDelegate
extension BluetoothManagerImpl: CBCentralManagerDelegate {

    func centralManagerDidUpdateState(_ central: CBCentralManager) {
        switch central.state {
        case .unknown:
            bluetoothStatus.send(.unknown)
        case .resetting:
            bluetoothStatus.send(.unknown)
        case .unsupported:
            bluetoothStatus.send(.unknown)
        case .unauthorized:
            bluetoothStatus.send(.notAuthorized)
        case .poweredOff:
            bleStatusObserver.send(false)
            bluetoothStatus.send(.poweredOff)
        case .poweredOn:
            bleStatusObserver.send(true)
            bluetoothStatus.send(.poweredOn)
        @unknown default:
            bluetoothStatus.send(.unknown)
        }
    }

    func centralManager(
        _ central: CBCentralManager,
        didDiscover peripheral: CBPeripheral,
        advertisementData: [String: Any],
        rssi RSSI: NSNumber
    ) {
        let localName = DeviceBluetoothConstants.PeripheralAdvertisementKeys.localName.rawValue

        guard let name = peripheral.name, let localName = advertisementData[localName] as? String else {
            return
        }

        let peripheralName = name.contains(RadiaCode.Model.defaultName) ? name : localName

        guard peripheralName.hasPrefix(RadiaCode.Model.defaultName) else {
            return
        }

        let splittedName = peripheralName.components(separatedBy: "#")

        let deviceId: String
        let deviceName: String

        if splittedName.count == 2 {
            deviceId = splittedName[1]
            deviceName = splittedName[0]
        } else {
            deviceId = peripheral.identifier.uuidString
            deviceName = RadiaCode.Model.defaultName
        }

        let foundDevice = RadiaCode(
            device: .init(identifier: deviceId, model: deviceName),
            signal: .init(doubleValue: RSSI.doubleValue),
            connection: peripheral
        )
        devicesObserver.send(foundDevice)
    }

    func centralManager(_ central: CBCentralManager, didConnect peripheral: CBPeripheral) {
        peripheral.discoverServices([Consts.radiaCodeServiceCBUUID])
        peripheral.readRSSI()
    }

    func centralManager(_ central: CBCentralManager, didDisconnectPeripheral peripheral: CBPeripheral, error: Error?) {
        if let continuation = disconnectContinuation {
            disconnectContinuation = nil
            if let disconnectError = error {
                continuation.resume(throwing: disconnectError)
            } else {
                continuation.resume()
            }
        }
    }
}

//
//  DeviceConnectionManager.swift
//  Radiacode
//
//  Created by Matvey Kozin on 11.09.2023.
//

import UIKit
import CoreBluetooth
import Combine
import FactoryKit

extension Container {
    var deviceConnectionManager: Factory<DeviceConnectionManager> {
        self { DeviceConnectionManagerImpl() }
            .singleton
    }
}

/// Состояние подключения прибора
typealias DeviceConnectionState = DeviceConnectionManagerImpl.ConnectionState

/// Менеджер подключений
protocol DeviceConnectionManager {

    /// События изменения подключения
    var connectionSubject: CurrentValueSubject<DeviceConnectionState, Never> { get }

    /// Запуск подключения
    func startConnect()

    /// Подключение к устройству
    /// - Parameters:
    ///   - radiacode: устройство
    func connect(radiacode: RadiaCode) async

    /// Ручное отключение от устройства
    func manualDisconnect() async
}

final class DeviceConnectionManagerImpl: DeviceConnectionManager {

    enum DeviceConnectionManagerError: Error {
        case timeout
    }

    /// Состояние подключения прибора
    enum ConnectionState: Equatable, CustomStringConvertible {
        /// Не проинициализированно
        case uninitialized
        /// Отсутсвует
        case empty
        /// Поиск
        case search(String)
        /// Переподключение
        case reconnect
        /// Не найден
        case notFound
        /// Подключен
        case connected
        /// Обновление прошивки
        case updatingFirmware
        /// Готов к использованию
        case ready(BluetoothDevice)
        /// Ошибка подключения
        case error
        /// Отключение от устройства и ошибка переподключения
        case disconnected

        var isConnected: Bool {
            switch self {
            case .connected, .ready, .updatingFirmware:
                true
            default:
                false
            }
        }

        var isReady: Bool {
            switch self {
            case .ready:
                true
            default:
                false
            }
        }

        var description: String {
            switch self {
            case .uninitialized:
                "Uninitialized"
            case .empty:
                "Empty"
            case .search(let device):
                "Search \(device)"
            case .reconnect:
                "Recconnect"
            case .notFound:
                "NotFound"
            case .connected:
                "Connected"
            case .updatingFirmware:
                "Updating"
            case .ready:
                "Ready"
            case .error:
                "Connection Error"
            case .disconnected:
                "Disconnected"
            }
        }

        var readyDevice: BluetoothDevice? {
            if case let .ready(device) = self {
                return device
            }
            return nil
        }
    }

    /// Способ подключения к устройству
    enum ConnectionType: Equatable {
        /// Автоматическое
        case auto
        /// Повторное
        case reconnect
        /// Ручное
        case manual
    }

    @Injected(\.deviceSetupManager) private var deviceSetupManager
    @Injected(\.deviceManager) private var deviceManager
    @Injected(\.deviceFoundManager) private var deviceFoundManager
    @Injected(\.bluetoothManager) private var bluetoothManager
    @Injected(\.analyticsEngine) private var analyticsEngine
    @Injected(\.deviceContainer) private var deviceContainer

    private let queue = DispatchQueue(label: "com.radiacode.ble.connection.timeout")
    private var isSearching = false

    let connectionSubject: CurrentValueSubject<ConnectionState, Never> = .init(.uninitialized)

    private var searchCancellable: AnyCancellable?

    private var cancellable: Set<AnyCancellable> = .init()

    func startConnect() {
        analyticsEngine.reportEvent(DeviceConnectionAnalyticsEvent.startSearching)

        guard let deviceId = deviceContainer.lastSavedDeviceId else {
            connectionSubject.send(.empty)
            return
        }

        cancellable.removeAll()
        connectionSubject.send(.search(deviceId))

        searchCancellable = deviceFoundManager.foundDeviceObserver
            .first(where: { $0.device.identifier == deviceId })
            .timeout(60 * 60, scheduler: queue, customError: { DeviceConnectionManagerError.timeout })
            .sink(
                receiveCompletion: { result in
                    switch result {
                    case .failure:
                        self.stopSearching()
                        self.connectionSubject.send(.notFound)
                    case .finished:
                        break
                    }
                }
                , receiveValue: { radiaCodeDevice in
                    self.searchCancellable = nil
                    self.stopSearching()
                    Task {
                        await self.connect(radiacode: radiaCodeDevice)
                    }
                }
            )
        isSearching = true
        deviceFoundManager.startSearching()
    }

    func connect(radiacode: RadiaCode) async {
        /// Отключение от предыдущего устройства
        await disconnect()

        let bluetoothDevice = BluetoothDevice(
            radiacode: radiacode.device,
            signal: radiacode.signal,
            peripheral: PeripheralImpl(cbPeripheral: radiacode.connection)
        )

        bluetoothDevice.peripheral?.connectionState
            .removeDuplicates()
            .dropFirst(2) /// Игнорируем изначальные состояния Disconnected и Connecting
            .sink { [weak self] state in
                guard let self = self else { return }
                self.analyticsEngine.reportEvent(
                    DeviceConnectionAnalyticsEvent.deviceConnection(identifier: bluetoothDevice.identifier, state: state)
                )
                switch state {
                case .connected:
                    self.connectionSubject.send(.connected)
                case .disconnected:
                    self.deviceManager.cancelRealTimeData()
                    Task {
                        await bluetoothDevice.stopCommands()
                    }
                    self.connectionSubject.send(.reconnect)
                    self.bluetoothManager.setupReconnection(device: radiacode.connection)
                case .connecting:
                    // Автоматическое переподключение
                    self.deviceSetupManager.setupInitialConnectionObserver()
                    self.startReconnectTimeout()
                case .disconnecting:
                    break
                }
            }
            .store(in: &cancellable)

        deviceSetupManager.connectedDeviceSubject
            .receive(on: DispatchQueue.main)
            .sink { [weak self] state in
                guard let self else { return }
                self.cancelReconnectTimeout()
                switch state {
                case .updating:
                    self.connectionSubject.send(.updatingFirmware)
                case .connected:
                    self.connectionSubject.send(.ready(bluetoothDevice))
                case .error:
                    self.connectionSubject.send(.error)
                }
            }
            .store(in: &cancellable)

        /// Сохранение устройства
        deviceContainer.lastSavedDeviceId = bluetoothDevice.identifier
        /// Сохранение устройства в менеджер для доступа к подключенному устройству и его первоначальной инициализации
        deviceSetupManager.setup(device: bluetoothDevice)

        /// Подключение к устройству по блютуз
        bluetoothManager.connect(device: radiacode.connection)
    }

    func manualDisconnect() async {
        connectionSubject.send(.empty)
        await disconnect()
    }

    /// Завершение автопоиска и подключения при необходимости
    private func stopSearching() {
        if isSearching {
            isSearching = false
            deviceFoundManager.stopSearching()
        }
    }

    private func disconnect() async {
        // Отменяем таймер
        cancelReconnectTimeout()

        // Удаляем подписки
        cancellable.removeAll()

        // Останавливаем поиск
        stopSearching()

        if let device = deviceContainer.current, let peripheral = device.peripheral?.cbPeripheral {
            // Удаляем устройство из базы для автоподключения
            deviceContainer.lastSavedDeviceId = nil
            if device.state != .disconnected {
                try? await bluetoothManager.disconnect(device: peripheral)
            }
        }
        await deviceSetupManager.reset()
    }

    private var reconnectTimeoutTask: Task<Void, Never>?

    private func startReconnectTimeout() {
        reconnectTimeoutTask?.cancel()
        reconnectTimeoutTask = Task {
            try? await Task.sleep(seconds: 60 * 10)
            guard !Task.isCancelled else { return }
            self.connectionSubject.send(.disconnected)
        }
    }

    private func cancelReconnectTimeout() {
        reconnectTimeoutTask?.cancel()
        reconnectTimeoutTask = nil
    }
}

