import Combine
import Foundation
import CoreBluetooth

typealias PeripheralConnectionState = PeripheralImpl.ConnectionState

protocol Peripheral: AnyObject {

    var cbPeripheral: CBPeripheral { get }

    var bluetoothSignal: PassthroughSubject<BluetoothSignal, Never> { get }

    var connectionState: AnyPublisher<PeripheralConnectionState, Never> { get }

    var peripheralState: CurrentValueSubject<PeripheralImpl.State, Never> { get }

    func write<T: BluetoothCommand>(command: T) async throws -> BluetoothRawStorage    

    func cancel()
}

final class PeripheralImpl: NSObject, Peripheral {

    enum PeripheralError: Error {
        case characteristic
        case storage
        case bleWriteError(Error)
    }

    enum ConnectionState: Equatable {
        case disconnected
        case disconnecting
        case connected
        case connecting

        static func from(state: CBPeripheralState) -> Self {
            switch state {
            case .disconnected: return .disconnected
            case .disconnecting: return .disconnecting
            case .connected: return .connected
            case .connecting: return .connecting
            @unknown default: return .disconnected
            }
        }
    }

    enum State {
        case started
        case ready
    }

    private var service: CBService?

    private var characteristicWrite: CBCharacteristic?
    private var characteristicNotify: CBCharacteristic?

    let peripheralState = CurrentValueSubject<State, Never>(.started)
    let bluetoothSignal: PassthroughSubject<BluetoothSignal, Never> = .init()

    private var bluetoothContinuation: CheckedContinuation<BluetoothRawStorage, Error>?

    private var bluetoothRawStorage: BluetoothRawStorage?
    private var commandPackage: [Data] = [] {
        didSet {
            guard let characteristicWrite else {
                finishContinuationWithError(error: PeripheralError.characteristic)
                return
            }
            if let pack = commandPackage.first {
                cbPeripheral.writeValue(pack, for: characteristicWrite, type: .withResponse)
            }
        }
    }

    var connectionState: AnyPublisher<ConnectionState, Never> {
        cbPeripheral.publisher(for: \.state)
            .map { ConnectionState.from(state: $0) }
            .eraseToAnyPublisher()
    }

    let cbPeripheral: CBPeripheral

    init(cbPeripheral: CBPeripheral) {
        self.cbPeripheral = cbPeripheral
        super.init()
        self.cbPeripheral.delegate = self
    }

    func write<T: BluetoothCommand>(command: T) async throws -> BluetoothRawStorage {
        try await withCheckedThrowingContinuation { continuation in
            bluetoothRawStorage = command.storageType.instance
            bluetoothContinuation = continuation
            commandPackage = command.requestPackage()
        }
    }

    func cancel() {
        finishContinuationWithError(error: CancellationError())
    }
}

// MARK: - CBPeripheralDelegate

extension PeripheralImpl: CBPeripheralDelegate {

    func peripheral(
        _ peripheral: CBPeripheral,
        didDiscoverCharacteristicsFor
        service: CBService,
        error: Error?
    ) {
        guard let characteristics = service.characteristics else {
            return
        }

        for characteristic in characteristics {
            if characteristic.properties.contains(.write) {
                self.characteristicWrite = characteristic
            }

            if characteristic.properties.contains(.notify) {
                peripheral.setNotifyValue(true, for: characteristic)
                characteristicNotify = characteristic
            }

            peripheral.discoverDescriptors(for: characteristic)
        }

        if characteristicWrite != nil {
            peripheralState.send(.ready)
        }
    }

    func peripheral(_ peripheral: CBPeripheral, didDiscoverServices error: Error?) {
        guard let services = peripheral.services else { return }

        for service in services {
            self.service = service
            peripheral.discoverCharacteristics(nil, for: service)
        }
    }

    func peripheral(_ peripheral: CBPeripheral, didReadRSSI RSSI: NSNumber, error: Error?) {
        bluetoothSignal.send(.init(doubleValue: RSSI.doubleValue))
        Task {
            try await Task.sleep(seconds: 4)
            self.cbPeripheral.readRSSI()
        }
    }

    func peripheral(_ peripheral: CBPeripheral, didUpdateValueFor characteristic: CBCharacteristic, error: Error?) {
        guard let data = characteristic.value else {
            finishContinuationWithError(error: CoreBluetooth.CBError(.unknown))
            return
        }

        guard let bluetoothRawStorage else {
            finishContinuationWithError(error: PeripheralError.storage)
            return
        }

        let bytes = data.asCollection
        bluetoothRawStorage.append(bytes: bytes)

        if bluetoothRawStorage.isLastPackage {
            if let continuation = bluetoothContinuation {
                bluetoothContinuation = nil
                continuation.resume(returning: bluetoothRawStorage)
            }
        }
    }

    func peripheral(_ peripheral: CBPeripheral, didWriteValueFor characteristic: CBCharacteristic, error: Error?) {
        if let error {
            finishContinuationWithError(error: PeripheralError.bleWriteError(error))
            return
        }
        if !commandPackage.isEmpty {
            commandPackage.remove(at: 0)
        }
    }

    private func finishContinuationWithError(error: Error) {
        guard let continuation = bluetoothContinuation else { return }
        bluetoothContinuation = nil
        continuation.resume(throwing: error)
    }

    func peripheralDidUpdateName(_ peripheral: CBPeripheral) {}
    func peripheral(_ peripheral: CBPeripheral, didModifyServices invalidatedServices: [CBService]) {}
    func peripheral(_ peripheral: CBPeripheral, didDiscoverIncludedServicesFor service: CBService, error: Error?) {}
    func peripheralDidUpdateRSSI(_ peripheral: CBPeripheral, error: Error?) {}
    func peripheral(_ peripheral: CBPeripheral, didUpdateValueFor descriptor: CBDescriptor, error: Error?) {}
    func peripheral(_ peripheral: CBPeripheral, didWriteValueFor descriptor: CBDescriptor, error: Error?) {}
    func peripheralIsReady(toSendWriteWithoutResponse peripheral: CBPeripheral) {}
    func peripheral(_ peripheral: CBPeripheral, didOpen channel: CBL2CAPChannel?, error: Error?) {}
    func peripheral(_ peripheral: CBPeripheral, didUpdateNotificationStateFor characteristic: CBCharacteristic, error: Error?) {}
    func peripheral(_ peripheral: CBPeripheral, didDiscoverDescriptorsFor characteristic: CBCharacteristic, error: Error?) {}
}

extension PeripheralImpl: CBPeripheralManagerDelegate {
    func peripheralManagerDidUpdateState(_ peripheral: CBPeripheralManager) {}
    func peripheralManager(_ peripheral: CBPeripheralManager, didReceiveRead request: CBATTRequest) {}
}

