import Foundation

/// Основная команда! Команда устанавливает связь устройств, что обеспечивает доступ ко всем командам протокола
struct SetExchangeCommand: BluetoothCommand {

    let request = BluetoothCommandRequest(
        command: .setExchange,
        payload: RadiaCode.hostID.asBytes
    )

    let storageType: StorageType = .system
}

// MARK: - Response

extension SetExchangeCommand {

    private enum Target: UInt32, CaseIterable {
        case radiaCode101Test = 0xDEDA0101
        case radiaCode101 = 0xFF03FF33
        case radiaCode102 = 0xDADA0105
    }

    struct Response {
        let targetId: UInt32
        let bufferMaxInboundSize: UInt16
        let bufferMaxOutboundSize: UInt16
        let isReady: Bool
        let lockedByInterface: UInt8?
    }

    var response: BluetoothCommandResponseBuilder<Response> {
        .init { storage in
            var bytes = storage.body

            // TODO: Добавить проверку на Таргет
            let targetId: UInt32 = bytes.toBinaryInteger(start: 0)
            bytes = Array(bytes.dropFirst(4))

            let bufferTX: UInt16 = bytes.toBinaryInteger(start: 0)
            bytes = Array(bytes.dropFirst(2))

            let bufferRX: UInt16 = bytes.toBinaryInteger(start: 0)
            bytes = Array(bytes.dropFirst(2))

            // TODO: Добавить проверку на проверку готовности устройства
            var isReady = true
            var lockedByInterface: UInt8 = 0
            if bytes.count > 0 {
                let readyForExchange: UInt8 = bytes.toBinaryInteger(start: 0)
                lockedByInterface = bytes.toBinaryInteger(start: 1)
                isReady = readyForExchange != 0
            }

            return .init(
                targetId: targetId,
                bufferMaxInboundSize: bufferTX,
                bufferMaxOutboundSize: bufferRX,
                isReady: isReady,
                lockedByInterface: lockedByInterface
            )
        }
    }
}
